import{fencedCodeBlockMatcher,frontmatterMatcher,inlineCodeMatcher}from"./compilers.js";const mdxDependencies=["@mdx-js/esbuild","@mdx-js/loader","@mdx-js/mdx","@mdx-js/node-loader","@mdx-js/preact","@mdx-js/react","@mdx-js/rollup","@mdx-js/vue","remark-mdx"],condition=e=>mdxDependencies.some(e),mdxImportMatcher=/^import[^'"]+['"][^'"]+['"]/gm,compiler=e=>[...e.replace(frontmatterMatcher,"").replace(fencedCodeBlockMatcher,"").replace(inlineCodeMatcher,"").matchAll(mdxImportMatcher)].join("\n");export default{condition:condition,compiler:compiler};